// Test stackalloc with native-sized integers (nint / nuint)

Console.WriteLine($"nint size: {nint.Size} bytes");
Console.WriteLine($"nuint size: {nuint.Size} bytes");

// stackalloc Span<nint>
Span<nint> signed = stackalloc nint[5];
for (int i = 0; i < signed.Length; i++)
    signed[i] = i * 10;

Console.WriteLine("\nSpan<nint> via stackalloc:");
foreach (var val in signed)
    Console.Write($"  {val}");
Console.WriteLine();

// stackalloc Span<nuint>
Span<nuint> unsigned = stackalloc nuint[5];
for (int i = 0; i < unsigned.Length; i++)
    unsigned[i] = (nuint)(i * 100);

Console.WriteLine("\nSpan<nuint> via stackalloc:");
foreach (var val in unsigned)
    Console.Write($"  {val}");
Console.WriteLine();

Console.WriteLine("\n✓ stackalloc with nint/nuint works!");

